module counter_with_enable(
    input               clk,
    input               rst,
    input               enable,

    output reg [7:0]    count
);
  wire _tap_clk = clk & {1{1'b1}};


always@(posedge clk) begin
    if (rst)
        count <= 8'b00000000;
    else if (enable)
        count <= count + 1;
end

endmodule
